<?php declare(strict_types=1); namespace Database\Factories\Confectionery; use App\Domains\Confectionery\Models\Confectionery; use Illuminate\Database\Eloquent\Factories\Factory; final class ConfectioneryFactory extends Factory { protected $model = Confectionery::class; public function definition(): array { return ['name' => $this->faker->words(2, true), 'sku' => strtoupper('CONF-' . $this->faker->bothify('####')), 'category' => $this->faker->randomElement(['cake', 'pastry', 'chocolate', 'candy', 'cookie', 'donut']), 'price' => $this->faker->numberBetween(50000, 150000), 'current_stock' => $this->faker->numberBetween(30, 200), 'min_stock_threshold' => 20, 'ingredients' => ['sugar', 'flour', 'butter', 'eggs'], 'allergens' => ['gluten', 'dairy', 'nuts'], 'rating' => $this->faker->randomFloat(1, 3.5, 5), 'review_count' => $this->faker->numberBetween(30, 250), 'status' => 'active', 'correlation_id' => \Illuminate\Support\Str::uuid()->toString(), 'tags' => ['confectionery', 'fresh'], 'meta' => []]; } public function premium(): self { return $this->state(['price' => $this->faker->numberBetween(120000, 300000), 'category' => 'cake']); } public function budget(): self { return $this->state(['price' => $this->faker->numberBetween(50000, 80000)]); } }
